SELECT
    biz_id as businessId,
    count(*) as likeCount,
    EXISTS(SELECT * FROM tb_like WHERE biz_type = #{bizType} AND biz_id = #{businessId} AND user_id = #{userId}) as isLiked
FROM tb_like
WHERE
    biz_type = #{bizType}
  AND
    biz_id IN #{businessIds}
GROUP BY biz_id;
